-- ============================================================
-- product_instagram data import
-- Source: Foursixty export (krost-business-furniture feed), generated 2026-07-06
-- Rows: 1556 across 169 products, 769 Instagram posts
--
-- Safe to run once on a database where the product_instagram
-- table exists (CreateProductInstagram migration). Re-running
-- will duplicate rows - TRUNCATE the table first if re-importing.
-- ============================================================

-- Captions contain emoji (4-byte UTF-8); force the connection charset
-- so older clients don't reject them with error 1366.
SET NAMES utf8mb4;

-- Some signed Instagram CDN thumbnail URLs exceed 500 chars (max 580).
-- Widen the column before inserting (no-op if already 1000).
ALTER TABLE `product_instagram` MODIFY `thumbnail_url` varchar(1000) DEFAULT NULL;

START TRANSACTION;

















COMMIT;

-- Verify: expect total=1556, products=169
SELECT COUNT(*) AS total, COUNT(DISTINCT product_id) AS products FROM `product_instagram`;
